+        let mut buf = Buffer::new(30, 4);
+        let blank_cell = *buf.get(0, 0).unwrap();
+        dbg.render_debug(Rect::new(0, 0, 30, 4), &mut buf);
+        assert_eq!(*buf.get(0, 0).unwrap(), blank_cell);
